// ============================================================
// STATE DETAIL DATA — Apana Store
// Unique per-state data for the Bharat → State Detail screen.
// Each state has: banners, tab-specific sub-categories & products, stores.
// Backend: GET /api/customer/bharat/state/:key
// ============================================================

export interface StateBanner {
  id: string; title: string; subtitle: string;
  tag: string; bg: string; accent: string; icon: string;
}
export interface StateSubCat {
  key: string; label: string; icon: string; bg: string;
}
export interface StateProduct {
  id: string; name: string; unit: string;
  price: number; bg: string; icon: string; badge?: string;
}
export interface StateStore {
  id: string; name: string; category: string; area: string;
  icon: string; bg: string; badge: string;
  badgeBg: string; badgeColor: string; rating: number;
}
export interface StateTabData {
  subCats: StateSubCat[];
  products: StateProduct[];
}
export interface StateDetailData {
  banners: StateBanner[];
  tabs: Record<string, StateTabData>;
  stores: StateStore[];
}

const DATA: Record<string, StateDetailData> = {};

/**
 * Fetches state-specific detail data asynchronously.
 * Simulates an API call with a delay.
 */
export async function fetchStateData(key: string): Promise<StateDetailData> {
  // Simulate network latency (500ms to 1.5s)
  await new Promise(resolve => setTimeout(resolve, 600 + Math.random() * 600));
  
  const data = DATA[key] ?? DATA["default"];
  return JSON.parse(JSON.stringify(data)); // Return a deep clone to simulate immutability from API
}

